                { id: 7, title: "Modal can", concept: "Ability permission possibility", structure: ["S can verb", "S cannot verb"], examples: ["I can swim", "Cant park here"], tips: "can always base verb" },
                { id: 8, title: "Future will", concept: "Future actions states", structure: ["S will verb", "S wont verb"], examples: ["Will visit next week"], tips: "will base verb only" },
                { id: 9, title: "Future going to", concept: "Plans signs future", structure: "S am is are going to verb", examples: ["Going to study tonight"], tips: "going to = plan/intention" },
                { id: 10, title: "Prepositions", concept: "Time place direction", structure: ["at time on date in year", "by transport with tool"], examples: ["at 7pm Monday 2024", "by bus pen"], tips: "at point on day in period" }
