                { id: 17, title: "Will for predictions", concept: "Guessing about future", structure: ["S will probably verb", "I think S will verb"], examples: ["Will probably rain", "Think will win"], tips: "use probably/think/I believe with will" },
                { id: 18, title: "Be able to", concept: "Future ability", structure: ["S will be able to verb", "S wont be able to verb"], examples: ["Be able to fly", "Wont be able drive"], tips: "be able to = can future form" },
                { id: 19, title: "More/Fewer/Less", concept: "Future comparisons", structure: ["more + count/uncount", "fewer + countable", "less + uncountable"], examples: ["More people fewer cars less pollution"], tips: "fewer for countable less uncountable" },
                { id: 20, title: "In + time expression", concept: "Future time marker", structure: ["in + period from now", "after + point time"], examples: ["In ten years after school"], tips: "in = future after = past sequence" }
